import { Link } from "react-router-dom";

function TarjetaAmpliada(props) {

    return (
        <div class="tarjeta-ampliada">
            <img src={props.img} alt={props.titulo} />
            <div class="t-a-tarjeta-cont">
                <div class="t-a-texto-tarjeta">
                    <h3>{props.titulo}</h3>
                    <p>{props.precio}</p>
                    <p>{props.descripcion}</p>
                </div>
                <div class="t-a-button-cont">
                    <button><Link to={`/Productos/${props.id}`}>Ver Menos...</Link></button>
                    <button><img src="/add-carrito.svg" alt="Carrito" /></button>
                </div>
            </div>
        </div>
    )
}

export default TarjetaAmpliada;
